1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	const CURSED_SURCHARGE_PERCENT = 50;
4	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_PERCENT = 20;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_PRICE = 60;
21	
22	const itemBasePremium = (item: any): number => BASE_PREMIUMS[item.type];
23	
24	const sumItemPremiums = (items: any[]): number =>
25	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
26	
27	const groupByType = (items: any[]): Record<string, any[]> =>
28	  items.reduce((groups, item) => {
29	    (groups[item.type] ||= []).push(item);
30	    return groups;
31	  }, {} as Record<string, any[]>);
32	
33	const isCompleteBlock = (type: string, group: any[]): boolean =>
34	  COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE;
35	
36	const groupPremium = (type: string, group: any[]): number =>
37	  isCompleteBlock(type, group) ? BLOCK_PRICE : sumItemPremiums(group);
38	
39	const calculateBasePremium = (items: any[]): number =>
40	  Object.entries(groupByType(items)).reduce(
41	    (total, [type, group]) => total + groupPremium(type, group),
42	    0
43	  );
44	
45	const percentOf = (amount: number, percent: number): number =>
46	  (amount * percent) / 100;
47	
48	type Rule<T> = { applies: (target: T) => boolean; percent: number };
49	
50	const ITEM_SURCHARGE_RULES: Rule<any>[] = [
51	  { applies: (item) => item.cursed, percent: CURSED_SURCHARGE_PERCENT },
52	  {
53	    applies: (item) => item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
54	    percent: HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
55	  },
56	];
57	
58	const FOLLOW_UP_DISCOUNT_PERCENT = 15;
59	
60	type PolicyContext = { customer: any; isFollowUp: boolean };
61	
62	const POLICY_MODIFIER_RULES: Rule<PolicyContext>[] = [
63	  { applies: () => true, percent: FIRST_INSURANCE_SURCHARGE_PERCENT },
64	  {
65	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
66	    percent: -LOYALTY_DISCOUNT_PERCENT,
67	  },
68	  {
69	    applies: ({ isFollowUp }) => isFollowUp,
70	    percent: -FOLLOW_UP_DISCOUNT_PERCENT,
71	  },
72	];
73	
74	const sumRulePercentages = <T>(rules: Rule<T>[], target: T, base: number): number =>
75	  rules.reduce(
76	    (sum, rule) => sum + (rule.applies(target) ? percentOf(base, rule.percent) : 0),
77	    0
78	  );
79	
80	const itemSurcharge = (item: any): number =>
81	  sumRulePercentages(ITEM_SURCHARGE_RULES, item, itemBasePremium(item));
82	
83	const calculateItemSurcharges = (items: any[]): number =>
84	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
85	
86	const calculatePolicyModifiers = (context: PolicyContext, policyBase: number): number =>
87	  sumRulePercentages(POLICY_MODIFIER_RULES, context, policyBase);
88	
89	const quotePremium = (items: any[], context: PolicyContext): number => {
90	  const policyBase = calculateBasePremium(items);
91	  const itemSurcharges = calculateItemSurcharges(items);
92	  const policyModifiers = calculatePolicyModifiers(context, policyBase);
93	  return Math.ceil(policyBase + policyModifiers + itemSurcharges + PROCESSING_FEE);
94	};
95	
96	const processStep = (step: any, index: number, customer: any) => ({
97	  premium: quotePremium(step.items, { customer, isFollowUp: index > 0 }),
98	});
99	
100	export const runScenario = (scenario: any): unknown => ({
101	  results: scenario.steps.map((step: any, index: number) =>
102	    processStep(step, index, scenario.customer)
103	  ),
104	});
