const calculateInsuranceSum = (items: any[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const calculateDamagePayout = (damage: any): number =>
  Math.max(0, Math.floor(damage.amount - DEDUCTIBLE));

const processClaim = (step: any, policies: any[]) => {
  const policy = policies[step.policy];
  const totalDamagePayout = step.incident.damages.reduce(
    (sum: number, damage: any) => sum + calculateDamagePayout(damage),
    0
  );
  const payout = Math.min(totalDamagePayout, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

const processQuote = (step: any, index: number, customer: any, policies: any[]) => {
  const premium = quotePremium(step.items, { customer, isFollowUp: index > 0 });
  const insuranceSum = calculateInsuranceSum(step.items);
  policies.push({ items: step.items, insuranceSum, remainingCap: CAP_MULTIPLIER * insuranceSum });
  return { premium };
};

const processStep = (step: any, index: number, customer: any, policies: any[]) =>
  step.op === "claim"
    ? processClaim(step, policies)
    : processQuote(step, index, customer, policies);

export const runScenario = (scenario: any): unknown => {
  const policies: any[] = [];
  return {
    results: scenario.steps.map((step: any, index: number) =>
      processStep(step, index, scenario.customer, policies)
    ),
  };
};
